SELECT upgrade.upgrade, count(*) AS change FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade != 0) AS upgrade JOIN (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade = 0) AS baseline ON baseline.bldg_id = upgrade.bldg_id WHERE baseline.applicability = true AND upgrade.applicability = true AND coalesce(baseline."out.electricity.total.energy_consumption" - upgrade."out.electricity.total.energy_consumption", -1) < 0.001 AND coalesce(baseline."out.natural_gas.total.energy_consumption" - upgrade."out.natural_gas.total.energy_consumption", -1) < 0.001 AND coalesce(baseline."out.fuel_oil.total.energy_consumption" - upgrade."out.fuel_oil.total.energy_consumption", -1) < 0.001 AND coalesce(baseline."out.propane.total.energy_consumption" - upgrade."out.propane.total.energy_consumption", -1) < 0.001 AND NOT (coalesce(abs(upgrade."out.electricity.total.energy_consumption" - baseline."out.electricity.total.energy_consumption"), 0) < 0.001 AND coalesce(abs(upgrade."out.natural_gas.total.energy_consumption" - baseline."out.natural_gas.total.energy_consumption"), 0) < 0.001 AND coalesce(abs(upgrade."out.fuel_oil.total.energy_consumption" - baseline."out.fuel_oil.total.energy_consumption"), 0) < 0.001 AND coalesce(abs(upgrade."out.propane.total.energy_consumption" - baseline."out.propane.total.energy_consumption"), 0) < 0.001) GROUP BY 1 ORDER BY 1